import React, { useEffect } from 'react'
import { useDispatch, useSelector } from 'react-redux'

import Item from './Item'
import ItemCreate from './ItemCreate'
import ItemCreateForm from './ItemCreateForm'

const ItemsList = ({category, categoryId, items}) => {
    
    return (
        <div className='itemsListElements'>
            <h4 className='itemTitle'>Items to discuss at the next {category.description}</h4>
            {items.length==0 ? <p className='infoText'>Add a new item you want to discuss regarding the {category.description}</p>
            : 
            items.map(item => <Item key={item.id} item={item}/>)
            }
            <ItemCreate category={category}/>
        </div>
    )
}

export default ItemsList