import React from 'react'

import { useDispatch, useSelector } from 'react-redux'
import { deactivateNote } from '../../reducers/NotesReducer'
import { unselectNote } from '../../reducers/selectNoteReducer'

import NoteItemRight from './NoteItemRight'


const NoteDescription = () => {
    const dispatch = useDispatch()

    const selectedNote = useSelector(state => state.selectedNote)


    const handleDone = () => {
        const itemObject = {id:selectedNote.id}
        dispatch(deactivateNote(itemObject))
        dispatch(unselectNote())
    }

    if (!selectedNote) {
        return null
    }

    
    return (
        <div className='noteRight'>
            <NoteItemRight note={selectedNote}/>
            <div className='buttonDeleteNote'>
                <button className='buttonLight' onClick={handleDone}>delete</button>
            </div>
        </div>
    )
}

export default NoteDescription