import React from 'react'
import { useDispatch, useSelector } from 'react-redux'

import { updateStatusItemProject } from '../../reducers/itemsProjectsReducer'

const ItemProject = ({item}) => {

    const dispatch = useDispatch()

    const status = useSelector(state => state.status)

    const handleChange = (e) => {
        dispatch(updateStatusItemProject({id:item.id, status:e.target.value}))
    }

    return (
        <div>
            <p>{item.title}</p>
            <select name="status" defaultValue={item.status} onChange={(e) => handleChange(e)}>
                {status.map(stat => <option key={stat.id} value={stat.id}>{stat.description}</option> )}
                {/* {status.map((stat) => (
                    stat.id === item.status ?
                        <option key={stat.id} value={stat.id}>{stat.description}</option>
                        :
                        <option key={stat.id} value={stat.id}>{stat.description}</option>
                ))} */}
            </select>
        </div>
    )
}



export default ItemProject