import React from 'react'
import { useDispatch } from 'react-redux'

import {projectSelect} from '../../reducers/projectSelectedReducer'

const ProjectsListItem = ({project}) => {

    const dispatch = useDispatch()

    const handleClick = (e) => {
        e.preventDefault()
        dispatch(projectSelect(project.id))
    }

    return (
        <div>
            <button onClick={handleClick}>{project.projectName}</button>
        </div>
    )
}

export default ProjectsListItem