export const selectNote = (item) => {
    return async dispatch => {
        dispatch({
            type: "SELECT_NOTE",
            data: item
            })
    }
}

export const unselectNote = () => {
    return async dispatch => {
        dispatch({
            type: "UNSELECT_NOTE",
            data: null
            })
    }
}
const selectNoteReducer = (state=null, action) => {
    switch(action.type) {
        case 'SELECT_NOTE':
            return action.data
        case 'UNSELECT_NOTE':
            return action.data
        default:
            return state
    }
}

export default selectNoteReducer