import React, { useEffect } from 'react'
import { useDispatch, useSelector } from 'react-redux'

import {
  Switch,
  Route,
  Link,
  Redirect
} from "react-router-dom"

import { getUserInfo } from './reducers/userReducer'

import Notification from "./components/Notification"
import LoginForm from './components/login/LoginForm'
import AccountForm from './components/login/AccountForm'
import UserInfo from './components/login/UserInfo'
import Header from './components/navigation/Header'
import Items from './components/item/Items'
import Projects from './components/project/Projects'
import ToDos from './components/todo/ToDos'
import Notes from './components/note/Notes'
import ToDoCreateForm from './components/todo/ToDoCreateForm'
import ItemCreateForm from './components/item/ItemCreateForm'

const App = () => {

  const dispatch = useDispatch()

  useEffect(() => {
    dispatch(getUserInfo())
  }, [dispatch])


  const user = useSelector(state => state.user)

  return (
    <div>
    
    <Header user={user}/>

      <Switch>

        <Route path='/profile'>
            {user === null? <Redirect to="/signup" /> : <UserInfo /> }         
          </Route>

        <Route path='/signin'>
          {user === null ? <div><LoginForm /><Notification /></div> : <Redirect to="/profile" />}         
        </Route>

        <Route path='/signup'>
          {user === null ? <div><AccountForm /><Notification /></div>  : <Redirect to="/profile" />}         
        </Route>

        <Route path='/notes'>
          <Notes />
        </Route>

        <Route path='/todos'>
          <ToDos />
          <ToDoCreateForm />
        </Route>
        
        <Route path='/items'>
          <Items />
          <ItemCreateForm />
        </Route>

        <Route path='/projects'>
            <Projects />
        </Route>

        <Route path='/' >
          <Notification />
        </Route>

      </Switch>

    </div>
  )
}

export default App;
