import React, {useState, useEffect} from 'react'

import { useDispatch } from 'react-redux'
import { updateNote } from '../../reducers/NotesReducer'


const NoteItemRight = ({note}) => {
    const dispatch = useDispatch()

    const [title, setTitle] = useState('')
    const [description, setDescription] = useState('')

    useEffect(() => {
        setTitle(note.title)
        setDescription(note.description)
      }, [note])


    // const handleSave = () => {
    //     const itemObject = {id:note.id, title:title, description:description}
    //     dispatch(updateNote(itemObject))
    // }

    const handleSaveAutoTitle = (e) => {
        setTitle(e.target.value)
        const itemObject = {id:note.id, title:e.target.value, description:description}
        setTimeout(() => {
        dispatch(updateNote(itemObject))
          }, 500);
    }

    const handleSaveAutoDesc = (e) => {
        setDescription(e.target.value)
        const itemObject = {id:note.id, title:title, description:e.target.value}
        setTimeout(() => {
        dispatch(updateNote(itemObject))
          }, 500);
    }

    // const tx = document.getElementsByTagName("textarea");
    // for (let i = 0; i < tx.length; i++) {
    // tx[i].setAttribute("style", "height:" + (tx[i].scrollHeight) + "px;overflow-y:hidden;");
    // tx[i].addEventListener("input", OnInput, false);
    // }

    // function OnInput() {
    // this.style.height = "auto";
    // this.style.height = (this.scrollHeight) + "px";
    // }

    return (
        <div>
            <div className='noteTitle'>
                <input className="noteTitleFont" type="text" placeholder="title" value={title} onChange={handleSaveAutoTitle} />   
            </div>
            <div className='noteDesc'>
                <textarea placeholder='note details' value={description} onChange={handleSaveAutoDesc} rows="1" cols="50"/>
            </div>
            {/* <div>
                <button className='buttonLight' onClick={handleSave}>save</button>
            </div> */}
    </div>
    )
}

export default NoteItemRight