import React, {useState} from 'react'
import { useDispatch, useSelector } from 'react-redux'

import { createItemToDo } from '../../reducers/itemsToDoReducer'


const ToDoCreateForm = () => {

    const dispatch = useDispatch()

    const [description, setDescription] = useState('')

    const handleCreateItem = (e) => {
        e.preventDefault()
        const itemObject = {description:description}
        dispatch(createItemToDo(itemObject))
        setDescription('')
    }

    // const tx = document.getElementsByTagName("textarea");
    // for (let i = 0; i < tx.length; i++) {
    //     tx[i].setAttribute("style", "height:" + (tx[i].scrollHeight) + "px;overflow-y:hidden;");
    //     tx[i].addEventListener("input", OnInput, false);
    // }

    // function OnInput() {
    // this.style.height = "auto";
    // this.style.height = (this.scrollHeight) + "px";
    // }
    
    return (
        <div className='bottomFormGlobal'>
            <form onSubmit={handleCreateItem}>
                <div className='createFormLeft'>
                {/* <textarea  placeholder='new to do' value={description} onChange={(e) => setDescription(e.target.value)} /> */}
                <input type="text" placeholder='new to do' value={description} onChange={(e) => setDescription(e.target.value)} />
                <button type='submit'>Create</button>
                </div>
            </form>
        </div>
    )
}

export default ToDoCreateForm