import React, { useEffect } from 'react'
import { useDispatch, useSelector } from 'react-redux'

import {getUserCategories} from '../../reducers/categoriesReducer'
import { getUserItemsCategory } from '../../reducers/itemsCategoriesReducer'

import ItemsList from './ItemsList'
import ItemCreateForm from './ItemCreateForm'

const Items = () => {
    const dispatch = useDispatch()

    const user = useSelector(state => state.user)
    const categories = useSelector(state => state.categories)
    const itemsCategories = useSelector(state => state.itemsCategories)

    useEffect(() => {
        dispatch(getUserCategories())
        dispatch(getUserItemsCategory())
      }, [dispatch])


    if (!user) {
        return null
    }
    
    return (
        <div className='containerGlobal'>
            <div className='itemList'>        
            {categories.map(cat => <ItemsList key={cat.id} categoryId={cat.id} category={cat}  items={itemsCategories.filter(item => item.category === cat.id)}/>)}
            {/* <ItemCreateForm /> */}
            </div>
         </div>
    )
}

export default Items