import React, {useState, useEffect} from 'react'

// import done from '../../files/done.png';
import { useDispatch } from 'react-redux'

import {deactivateItemCategory, updateItemCategory} from '../../reducers/itemsCategoriesReducer'

const Item = ({item}) => {
    const dispatch = useDispatch()

    const [description, setDescription] = useState('')

    useEffect(() => {
        setDescription(item.description)
      }, [item])

    const handleDone = (e) => {
        // console.log(e.target.checked)
        const itemObject = {id:item.id}
        dispatch(deactivateItemCategory(itemObject))
    }

    const handleSaveAutoDesc = (e) => {
        setDescription(e.target.value)
        const itemObject = {id:item.id, description:e.target.value}
        setTimeout(() => {
        dispatch(updateItemCategory(itemObject))
          }, 500);
    }


    return (
        <div className='item'>
            <div>
                <input type="checkbox" className='checkboxClass' title='Done/Remove' onClick={(e) => handleDone(e)} />
            </div>
            <div className='lineItem'>
                {/* <p>{item.description}</p> */}
                <input type="text" placeholder="title" value={description} onChange={handleSaveAutoDesc} />   
            {/* <img onClick={handleDone} className='' src={done} alt='Done'/> */}
            </div>
        </div>
    )
}

export default Item