import React, {useState} from 'react'
import { useDispatch, useSelector } from 'react-redux'

import { createProject } from '../../reducers/projectReducer'


const ProjectCreateForm = () => {

    const dispatch = useDispatch()

    const [title, setTitle] = useState('')

    const handleCreateItem = (e) => {
        e.preventDefault()
        const itemObject = {projectName: title}
        dispatch(createProject(itemObject))
        setTitle('')
    }

    return (
        <div>
            <h2>Create a project</h2>

            <form onSubmit={handleCreateItem}>
                <input type="text" placeholder="project name" value={title} onChange={(e) => setTitle(e.target.value)} /> 
                <button type='submit'>Create</button>
            </form>
        </div>
    )
}

export default ProjectCreateForm