import React, {useState} from 'react'
import { useDispatch, useSelector } from 'react-redux'

import { createItemCategory } from '../../reducers/itemsCategoriesReducer'

import {hideAddItem} from '../../reducers/addItemReducer'

const ItemCreateForm = () => {

    const dispatch = useDispatch()
    const category = useSelector(state => state.addItem)

    const [description, setDescription] = useState('')


    const handleCreateItem = (e) => {
        e.preventDefault()
        const itemObject = {description:description, category:category.id}
        dispatch(hideAddItem())
        dispatch(createItemCategory(itemObject))
        setDescription('')
    }

    const handleClickRemove = (e) => {
        e.preventDefault()
        dispatch(hideAddItem())
    }

    if (!category) {
        return null
    }

 
    // const tx = document.getElementsByTagName("textarea");
    // for (let i = 0; i < tx.length; i++) {
    // tx[i].setAttribute("style", "height:" + (tx[i].scrollHeight) + "px;overflow-y:hidden;");
    // tx[i].addEventListener("input", OnInput, false);
    // }

    // function OnInput() {
    // this.style.height = "auto";
    // this.style.height = (this.scrollHeight) + "px";
    // }
    

    return (
        <div className='bottomFormGlobal'>
            {/* <h2>Create an item for {category.description}</h2> */}

            <form onSubmit={handleCreateItem}>
            <div className='createFormLeft'>
                {/* <textarea  placeholder='your description' value={description} onChange={(e) => setDescription(e.target.value)} rows="1" cols="50"/> */}
                <input type="text" placeholder={`new item related to ${category.description}`} value={description} onChange={(e) => setDescription(e.target.value)} />
                <button type='submit'>Create</button>
                <button className='buttonLight' onClick={handleClickRemove}>cancel</button>
            </div>
            </form>
        </div>
    )
}

export default ItemCreateForm